+    #[test]
+    fn series_isna_notna_flags_null_and_nan() {
+        let s = Series::from_values(
+            "vals",
+            vec![1_i64.into(), 2_i64.into(), 3_i64.into(), 4_i64.into()],
+            vec![
+                Scalar::Int64(10),
+                Scalar::Null(NullKind::Null),
+                Scalar::Float64(f64::NAN),
+                Scalar::Bool(false),
+            ],
+        )
+        .unwrap();
+
+        let isna = s.isna().unwrap();
+        assert_eq!(
+            isna.values(),
+            &[
+                Scalar::Bool(false),
+                Scalar::Bool(true),
+                Scalar::Bool(true),
+                Scalar::Bool(false)
+            ]
+        );
+
+        let notna = s.notna().unwrap();
+        assert_eq!(
+            notna.values(),
+            &[
+                Scalar::Bool(true),
+                Scalar::Bool(false),
+                Scalar::Bool(false),
+                Scalar::Bool(true)
+            ]
+        );
+    }
